import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"五运六气总纲","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/10-五运六气/01-五运六气总纲.md","filePath":"tcm-data/10-五运六气/01-五运六气总纲.md","lastUpdated":1781084559000}'),n={name:"tcm-data/10-五运六气/01-五运六气总纲.md"};function s(r,t,i,g,o,h){return l(),a("div",null,[...t[0]||(t[0]=[d(`<h1 id="五运六气总纲" tabindex="-1">五运六气总纲 <a class="header-anchor" href="#五运六气总纲" aria-label="Permalink to &quot;五运六气总纲&quot;">​</a></h1><blockquote><p>五运六气是《黄帝内经》的最高智慧 是天人合一思想在医学中的具体应用 &quot;不懂五运六气，捡遍方书何济？&quot;</p></blockquote><hr><h2 id="一、什么是五运六气" tabindex="-1">一、什么是五运六气？ <a class="header-anchor" href="#一、什么是五运六气" aria-label="Permalink to &quot;一、什么是五运六气？&quot;">​</a></h2><h3 id="五运——年运-天干所化" tabindex="-1">五运——年运（天干所化） <a class="header-anchor" href="#五运——年运-天干所化" aria-label="Permalink to &quot;五运——年运（天干所化）&quot;">​</a></h3><ul><li><strong>五运</strong>：木、火、土、金、水五行的运行</li><li>天干化五运：甲己化土、乙庚化金、丙辛化水、丁壬化木、戊癸化火</li><li>每运分<strong>太过</strong>（阳干）和<strong>不及</strong>（阴干）</li></ul><h3 id="六气——节气-地支所化" tabindex="-1">六气——节气（地支所化） <a class="header-anchor" href="#六气——节气-地支所化" aria-label="Permalink to &quot;六气——节气（地支所化）&quot;">​</a></h3><ul><li><strong>六气</strong>：风、寒、暑、湿、燥、火六种气候</li><li>地支化六气：子午少阴君火、丑未太阴湿土、寅申少阳相火、卯酉阳明燥金、辰戌太阳寒水、巳亥厥阴风木</li></ul><hr><h2 id="二、五运六气的基本框架" tabindex="-1">二、五运六气的基本框架 <a class="header-anchor" href="#二、五运六气的基本框架" aria-label="Permalink to &quot;二、五运六气的基本框架&quot;">​</a></h2><h3 id="_1-司天在泉" tabindex="-1">1. 司天在泉 <a class="header-anchor" href="#_1-司天在泉" aria-label="Permalink to &quot;1. 司天在泉&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年支</th><th style="text-align:left;">司天（主管上半年）</th><th style="text-align:left;">在泉（主管下半年）</th></tr></thead><tbody><tr><td style="text-align:left;">子·午</td><td style="text-align:left;">少阴君火</td><td style="text-align:left;">阳明燥金</td></tr><tr><td style="text-align:left;">丑·未</td><td style="text-align:left;">太阴湿土</td><td style="text-align:left;">太阳寒水</td></tr><tr><td style="text-align:left;">寅·申</td><td style="text-align:left;">少阳相火</td><td style="text-align:left;">厥阴风木</td></tr><tr><td style="text-align:left;">卯·酉</td><td style="text-align:left;">阳明燥金</td><td style="text-align:left;">少阴君火</td></tr><tr><td style="text-align:left;">辰·戌</td><td style="text-align:left;">太阳寒水</td><td style="text-align:left;">太阴湿土</td></tr><tr><td style="text-align:left;">巳·亥</td><td style="text-align:left;">厥阴风木</td><td style="text-align:left;">少阳相火</td></tr></tbody></table><h3 id="_2-主气-一年六步-固定不变" tabindex="-1">2. 主气（一年六步，固定不变） <a class="header-anchor" href="#_2-主气-一年六步-固定不变" aria-label="Permalink to &quot;2. 主气（一年六步，固定不变）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">次序</th><th style="text-align:left;">气</th><th style="text-align:left;">时段</th><th style="text-align:left;">节气</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>初之气</strong></td><td style="text-align:left;">厥阴风木</td><td style="text-align:left;">1月中-3月中</td><td style="text-align:left;">大寒→春分</td></tr><tr><td style="text-align:left;"><strong>二之气</strong></td><td style="text-align:left;">少阴君火</td><td style="text-align:left;">3月中-5月中</td><td style="text-align:left;">春分→小满</td></tr><tr><td style="text-align:left;"><strong>三之气</strong></td><td style="text-align:left;">少阳相火</td><td style="text-align:left;">5月中-7月中</td><td style="text-align:left;">小满→大暑</td></tr><tr><td style="text-align:left;"><strong>四之气</strong></td><td style="text-align:left;">太阴湿土</td><td style="text-align:left;">7月中-9月中</td><td style="text-align:left;">大暑→秋分</td></tr><tr><td style="text-align:left;"><strong>五之气</strong></td><td style="text-align:left;">阳明燥金</td><td style="text-align:left;">9月中-11月中</td><td style="text-align:left;">秋分→小雪</td></tr><tr><td style="text-align:left;"><strong>终之气</strong></td><td style="text-align:left;">太阳寒水</td><td style="text-align:left;">11月中-次年1月中</td><td style="text-align:left;">小雪→大寒</td></tr></tbody></table><h3 id="_3-客气-每年变动" tabindex="-1">3. 客气（每年变动） <a class="header-anchor" href="#_3-客气-每年变动" aria-label="Permalink to &quot;3. 客气（每年变动）&quot;">​</a></h3><p>客气加在主气之上，形成&quot;<strong>客主加临</strong>&quot;——就是这个年份的真实气候特征。</p><hr><h2 id="三、普光、普明的五运六气体质分析" tabindex="-1">三、普光、普明的五运六气体质分析 <a class="header-anchor" href="#三、普光、普明的五运六气体质分析" aria-label="Permalink to &quot;三、普光、普明的五运六气体质分析&quot;">​</a></h2><h3 id="普光-1982年正月初三丑时-壬戌年" tabindex="-1">普光：1982年正月初三丑时（壬戌年） <a class="header-anchor" href="#普光-1982年正月初三丑时-壬戌年" aria-label="Permalink to &quot;普光：1982年正月初三丑时（壬戌年）&quot;">​</a></h3><p><strong>年柱推算</strong>：</p><ul><li>1982年 → 壬戌年</li><li><strong>天干壬</strong>：丁壬化木，壬为阳干 → <strong>木运太过</strong></li><li><strong>地支戌</strong>：辰戌之年 → <strong>太阳寒水司天，太阴湿土在泉</strong></li></ul><p><strong>先天体质</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>木运太过 → 肝气偏旺</span></span>
<span class="line"><span>太阳寒水司天 → 先天寒气重（出生山东+北方）</span></span>
<span class="line"><span>太阴湿土在泉 → 后天脾土偏湿</span></span></code></pre></div><p><strong>解释普光的全部症状</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">运气因素</th><th style="text-align:left;">体质影响</th><th style="text-align:left;">症状</th></tr></thead><tbody><tr><td style="text-align:left;">木运太过</td><td style="text-align:left;">肝气旺→克脾土</td><td style="text-align:left;">肝脾痛、易怒</td></tr><tr><td style="text-align:left;">太阳寒水司天</td><td style="text-align:left;">先天肾阳不足</td><td style="text-align:left;">腰凉、脚冷、无力</td></tr><tr><td style="text-align:left;">太阴湿土在泉</td><td style="text-align:left;">脾湿内停</td><td style="text-align:left;">面色暗沉、阴囊湿、脚气</td></tr><tr><td style="text-align:left;">木郁化火</td><td style="text-align:left;">相火不降</td><td style="text-align:left;">血压高、口渴、前胸出汗</td></tr></tbody></table><h3 id="普明-1982年10月28日13-30-壬戌年九月十二未时" tabindex="-1">普明：1982年10月28日13:30（壬戌年九月十二未时） <a class="header-anchor" href="#普明-1982年10月28日13-30-壬戌年九月十二未时" aria-label="Permalink to &quot;普明：1982年10月28日13:30（壬戌年九月十二未时）&quot;">​</a></h3><p><strong>年柱</strong>：同普光——壬戌年（木运太过+寒水司天+湿土在泉） <strong>月柱</strong>：九月（戌月）→ 与年支戌重叠，<strong>土气加倍</strong><strong>时柱</strong>：未时 → 未属土</p><p><strong>先天体质</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>木运太过 → 肝气偏旺</span></span>
<span class="line"><span>太阳寒水司天 → 先天寒气</span></span>
<span class="line"><span>太阴湿土在泉 + 九月戌土 + 未时土 → 土气极重</span></span></code></pre></div><p><strong>解释普明的全部症状</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">运气因素</th><th style="text-align:left;">体质影响</th><th style="text-align:left;">症状</th></tr></thead><tbody><tr><td style="text-align:left;">木运太过</td><td style="text-align:left;">肝旺</td><td style="text-align:left;">烦躁、月经先期</td></tr><tr><td style="text-align:left;">太阳寒水</td><td style="text-align:left;">肾阳不足</td><td style="text-align:left;">手脚冷、经期腰凉</td></tr><tr><td style="text-align:left;">三重土气（年支+月+时）</td><td style="text-align:left;">脾虚湿盛</td><td style="text-align:left;">白带、腹胀、疲惫</td></tr></tbody></table><hr><h2 id="四、当前流年运气分析-2026年" tabindex="-1">四、当前流年运气分析（2026年） <a class="header-anchor" href="#四、当前流年运气分析-2026年" aria-label="Permalink to &quot;四、当前流年运气分析（2026年）&quot;">​</a></h2><p><strong>2026年：丙午年</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>天干丙</strong></td><td style="text-align:left;">丙辛化水，丙为阳干 → <strong>水运太过</strong></td></tr><tr><td style="text-align:left;"><strong>地支午</strong></td><td style="text-align:left;">子午之年 → <strong>少阴君火司天，阳明燥金在泉</strong></td></tr></tbody></table><h3 id="_2026年运气特点" tabindex="-1">2026年运气特点 <a class="header-anchor" href="#_2026年运气特点" aria-label="Permalink to &quot;2026年运气特点&quot;">​</a></h3><p><strong>水运太过</strong> → 寒冷偏重，要注意肾阳 <strong>少阴君火司天</strong> → 上半年火热偏多 <strong>阳明燥金在泉</strong> → 下半年燥气偏重</p><h3 id="对普光的影响" tabindex="-1">对普光的影响 <a class="header-anchor" href="#对普光的影响" aria-label="Permalink to &quot;对普光的影响&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">运气因素</th><th style="text-align:left;">对普光的影响</th><th style="text-align:left;">注意事项</th></tr></thead><tbody><tr><td style="text-align:left;">水运太过+普光本身水寒</td><td style="text-align:left;">寒上加寒 → 腰凉、膝盖痛</td><td style="text-align:left;">⭐ <strong>加强温阳</strong></td></tr><tr><td style="text-align:left;">上半年君火司天</td><td style="text-align:left;">相火不降可能加重（血压波动）</td><td style="text-align:left;">注意监测血压</td></tr><tr><td style="text-align:left;">下半年燥金在泉</td><td style="text-align:left;">脚后跟开裂可能加重</td><td style="text-align:left;">加强润肤</td></tr></tbody></table><h3 id="对普明的影响" tabindex="-1">对普明的影响 <a class="header-anchor" href="#对普明的影响" aria-label="Permalink to &quot;对普明的影响&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">运气因素</th><th style="text-align:left;">对普明的影响</th><th style="text-align:left;">注意事项</th></tr></thead><tbody><tr><td style="text-align:left;">水运太过</td><td style="text-align:left;">肾水受抑 → 月经周期可能更乱</td><td style="text-align:left;">加强补肾</td></tr><tr><td style="text-align:left;">上半年君火司天</td><td style="text-align:left;">潮热烦躁可能加重</td><td style="text-align:left;">加强潜降虚火</td></tr><tr><td style="text-align:left;">下半年燥金在泉</td><td style="text-align:left;">口干、皮肤干可能加重</td><td style="text-align:left;">加强润燥</td></tr></tbody></table><hr><h2 id="五、普光-普明各节气调整方案" tabindex="-1">五、普光/普明各节气调整方案 <a class="header-anchor" href="#五、普光-普明各节气调整方案" aria-label="Permalink to &quot;五、普光/普明各节气调整方案&quot;">​</a></h2><h3 id="_2026年剩余节气提醒" tabindex="-1">2026年剩余节气提醒 <a class="header-anchor" href="#_2026年剩余节气提醒" aria-label="Permalink to &quot;2026年剩余节气提醒&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">节气</th><th style="text-align:left;">日期</th><th style="text-align:left;">运气特点</th><th style="text-align:left;">普光</th><th style="text-align:left;">普明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>夏至</strong></td><td style="text-align:left;">6月21日</td><td style="text-align:left;">一阴生</td><td style="text-align:left;">避大汗</td><td style="text-align:left;">早睡</td></tr><tr><td style="text-align:left;"><strong>小暑·大暑</strong></td><td style="text-align:left;">7月</td><td style="text-align:left;">太阴湿土主气</td><td style="text-align:left;">⭐ 湿气最重！加强泄湿</td><td style="text-align:left;">注意带下</td></tr><tr><td style="text-align:left;"><strong>立秋·处暑</strong></td><td style="text-align:left;">8月</td><td style="text-align:left;">阳明燥金</td><td style="text-align:left;">开始养肺</td><td style="text-align:left;">开始养阴</td></tr><tr><td style="text-align:left;"><strong>秋分</strong></td><td style="text-align:left;">9月</td><td style="text-align:left;">阴气渐盛</td><td style="text-align:left;">早睡</td><td style="text-align:left;">养收敛</td></tr><tr><td style="text-align:left;"><strong>霜降·立冬</strong></td><td style="text-align:left;">10-11月</td><td style="text-align:left;">寒水</td><td style="text-align:left;">⭐ 注意腰腹保暖</td><td style="text-align:left;">冬补</td></tr></tbody></table><hr><h2 id="六、五运六气的日常应用" tabindex="-1">六、五运六气的日常应用 <a class="header-anchor" href="#六、五运六气的日常应用" aria-label="Permalink to &quot;六、五运六气的日常应用&quot;">​</a></h2><h3 id="_1-每年根据运气调整用药" tabindex="-1">1. 每年根据运气调整用药 <a class="header-anchor" href="#_1-每年根据运气调整用药" aria-label="Permalink to &quot;1. 每年根据运气调整用药&quot;">​</a></h3><p>例如2026年水运太过+寒水司天：</p><ul><li>普光的温阳药（附子干姜）可适当<strong>加量或延长疗程</strong></li><li>普明的补肾药（杜仲等）可<strong>加强</strong></li></ul><h3 id="_2-饮食随运气调整" tabindex="-1">2. 饮食随运气调整 <a class="header-anchor" href="#_2-饮食随运气调整" aria-label="Permalink to &quot;2. 饮食随运气调整&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">运气</th><th style="text-align:left;">饮食建议</th></tr></thead><tbody><tr><td style="text-align:left;">木运太过</td><td style="text-align:left;">多食甘味（健脾制木）</td></tr><tr><td style="text-align:left;">火运太过</td><td style="text-align:left;">多食咸味（补水制火）</td></tr><tr><td style="text-align:left;">土运太过</td><td style="text-align:left;">多食酸味（疏木制土）</td></tr><tr><td style="text-align:left;">金运太过</td><td style="text-align:left;">多食苦味（降火制金）</td></tr><tr><td style="text-align:left;">水运太过</td><td style="text-align:left;"><strong>多食甘温</strong>（温阳制水）→ 2026年建议</td></tr></tbody></table><h3 id="_3-养生随运气调整" tabindex="-1">3. 养生随运气调整 <a class="header-anchor" href="#_3-养生随运气调整" aria-label="Permalink to &quot;3. 养生随运气调整&quot;">​</a></h3><p>2026年（丙午年）全年养生重点：</p><ul><li><strong>全年</strong>：温肾阳（水运太过+普光本身肾寒）</li><li><strong>上半年</strong>：潜降相火（君火司天）</li><li><strong>下半年</strong>：润燥养阴（燥金在泉）</li></ul><hr><p><em>本条目为精简框架版。可扩展至逐年运气推演（未来10年）、司天方分析、运气方（三因司天方）详解等。</em></p>`,57)])])}const y=e(n,[["render",s]]);export{f as __pageData,y as default};
